worker_raw_output:
{
  "summary": "The Nginx configuration for the 'backend' upstream is pointing to port 8001, but the 'app' service is listening on port 8000. This mismatch causes Nginx to fail connecting to the upstream, resulting in 502 errors. The fix is to update the Nginx configuration to use the correct port for the 'app' service and then restart Nginx.",
  "actions": [
    {
      "type": "edit_file",
      "path": "nginx/nginx.conf",
      "operation": "replace_text",
      "old_text": "server app:8001;",
      "new_text": "server app:8000;"
    },
    {
      "type": "restart_compose_service",
      "service": "nginx"
    }
  ]
}

